<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> node </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> tree</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">root_node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">children</span><span style="color:#9399B2;">:</span></span>
