<span class="line"><span style="color:#CDD6F4;">            chunk_text </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> content</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">node</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">start_byte</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;">node</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">end_byte</span><span style="color:#9399B2;">]</span></span>
